const sourceItems = $('When Executed by Another Workflow').all();
const sourceRows = sourceItems.map(i => i.json);

const target_chat_id = '@bullpacksignal';
const sharedText = String($input.first()?.json?.content?.parts?.[0]?.text || '').trim();

if (!sourceRows.length) return [];

const groups = {};

for (const r of sourceRows) {
  const key = r.media_group_id
    ? `mg_${r.media_group_id}`
    : `single_${r.message_id}`;

  if (!groups[key]) groups[key] = [];
  groups[key].push(r);
}

const out = [];

for (const [groupKey, arr] of Object.entries(groups)) {
  arr.sort((a, b) => Number(a.message_id || 0) - Number(b.message_id || 0));

  const rowIds = arr
    .map(r => r.id || r.rowId || r._id)
    .filter(Boolean);

  if (arr.length === 1) {
    const r = arr[0];
    const type = String(r.type || "").trim();
    const file_id = r.file_id || null;

    if (type === "photo" && file_id) {
      out.push({
        json: {
          group_key: `${groupKey}_${target_chat_id}`,
          source_group_key: groupKey,
          send_method: "sendPhoto",
          payload: {
            chat_id: target_chat_id,
            photo: file_id,
            ...(sharedText ? { caption: sharedText } : {})
          },
          rows_to_mark: rowIds
        }
      });
      continue;
    }

    if (type === "video" && file_id) {
      out.push({
        json: {
          group_key: `${groupKey}_${target_chat_id}`,
          source_group_key: groupKey,
          send_method: "sendVideo",
          payload: {
            chat_id: target_chat_id,
            video: file_id,
            ...(sharedText ? { caption: sharedText } : {})
          },
          rows_to_mark: rowIds
        }
      });
      continue;
    }

    if (type === "document" && file_id) {
      out.push({
        json: {
          group_key: `${groupKey}_${target_chat_id}`,
          source_group_key: groupKey,
          send_method: "sendDocument",
          payload: {
            chat_id: target_chat_id,
            document: file_id,
            ...(sharedText ? { caption: sharedText } : {})
          },
          rows_to_mark: rowIds
        }
      });
      continue;
    }

    out.push({
      json: {
        group_key: `${groupKey}_${target_chat_id}`,
        source_group_key: groupKey,
        send_method: "sendMessage",
        payload: {
          chat_id: target_chat_id,
          text: sharedText || "Unsupported message type"
        },
        rows_to_mark: rowIds
      }
    });

    continue;
  }

  const media = arr
    .filter(r => r.file_id && ["photo", "video"].includes(String(r.type || "").trim()))
    .map((r, idx) => {
      const item = {
        type: String(r.type || "").trim(),
        media: r.file_id
      };

      if (idx === 0 && sharedText) {
        item.caption = sharedText;
      }

      return item;
    });

  if (!media.length) continue;

  out.push({
    json: {
      group_key: `${groupKey}_${target_chat_id}`,
      source_group_key: groupKey,
      media_group_id: arr[0].media_group_id || null,
      send_method: "sendMediaGroup",
      payload: {
        chat_id: target_chat_id,
        media
      },
      rows_to_mark: rowIds
    }
  });
}

return out;
